export function getCategoryBySlug(slug: string): OlxCategoryNode | undefined {
  return OLX_CATEGORIES.find((c) => c.slug === slug);
}

export function getCategoryById(id: number): OlxCategoryNode | undefined {
  return OLX_CATEGORIES.find((c) => c.id === id);
}

export function getL1Categories(): OlxCategoryNode[] {
  return OLX_CATEGORIES.filter((c) => c.parentId === null);
}

export function getChildCategories(parentId: number): OlxCategoryNode[] {
  return OLX_CATEGORIES.filter((c) => c.parentId === parentId);
}

export function categoryLabel(c: OlxCategoryNode, locale: "uk" | "en"): string {
  return locale === "uk" ? c.labelUk : c.labelEn;
}

/** Maps catalog legacy key to backend ListingCategory enum string */
export function legacyToListingCategoryKey(
  legacy: string,
): "electronics" | "clothing" | "books" | "digital" | "services" | "other" {
  if (legacy === "electronics") return "electronics";
  if (legacy === "clothing") return "clothing";
  if (legacy === "books") return "books";
  if (legacy === "digital") return "digital";
  if (legacy === "services") return "services";
  return "other";
}
